    """Output attribute value if present."""
    v = node.get_attr(attr_name)
    if v is None:
        return
    if base and node.name in ('a', 'link', 'area') and attr_name == 'href':
        v = resolve_url(base, v)
    out_stream.write(v.encode('utf-8'))
    out_stream.write(b'\n')


